// Map Givebutter payload → our shapes. ⚑ adjust field paths to Givebutter's actual schema.
const p = $json.body || $json;
const donor = {
  full_name: p.donor_name || p.first_name + ' ' + (p.last_name||''),
  email: (p.email||'').toLowerCase() || null,
  phone: p.phone || null,
  source: 'givebutter',
  type: p.donor_type || 'individual'
};
const donation = {
  external_id: p.transaction_id || p.id,
  amount: Number(p.amount),
  currency: p.currency || 'USD',
  channel: 'givebutter',
  is_recurring: !!p.recurring,
  status: (p.status||'succeeded'),
  donated_at: p.created_at || new Date().toISOString(),
  campaign_external: p.campaign_id || null
};
return [{ json: { donor, donation } }];
